function useMobile(){
  const[m,setM]=useState(window.innerWidth<700)
  useEffect(()=>{const h=()=>setM(window.innerWidth<700);window.addEventListener('resize',h);return()=>window.removeEventListener('resize',h)},[])
  return m
}

const fmtDate = iso => iso ? new Date(iso).toLocaleDateString('nb-NO',{day:'numeric',month:'long',year:'numeric'}) : ''
const initials = n => n.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase()

async function loadNews() {
  try { const r = await window.storage.get('pj:v7',true); if(r?.value) return JSON.parse(r.value) } catch{}
  return SEED
}
async function saveNews(arr) { try { await window.storage.set('pj:v7',JSON.stringify(arr),true) } catch{} }

/* ── SCALES SVG ── */
function Scales({size=28,color=CR}){
  return(
    <svg width={size} height={size} viewBox="0 0 100 100" fill="none">
      <circle cx="50" cy="10" r="5" fill={color}/>
      <rect x="47" y="10" width="6" height="32" fill={color}/>
      <rect x="18" y="42" width="64" height="5" rx="2.5" fill={color}/>
      <circle cx="18" cy="44.5" r="5" fill={color}/>
      <circle cx="82" cy="44.5" r="5" fill={color}/>
      <line x1="18" y1="49" x2="4"  y2="72" stroke={color} strokeWidth="4"/>
      <line x1="18" y1="49" x2="32" y2="72" stroke={color} strokeWidth="4"/>
      <path d="M4 72 Q18 78 32 72" stroke={color} strokeWidth="3.5" fill="none"/>
      <line x1="82" y1="49" x2="68" y2="75" stroke={color} strokeWidth="4"/>
      <line x1="82" y1="49" x2="96" y2="75" stroke={color} strokeWidth="4"/>
      <path d="M68 75 Q82 81 96 75" stroke={color} strokeWidth="3.5" fill="none"/>
    </svg>
  )
}

/* ── NAV ── */
function Nav({page,setPage,user,mobileOpen,setMobileOpen}){
  const [wide,setWide]=useState(window.innerWidth>920)
  useEffect(()=>{
    const h=()=>setWide(window.innerWidth>920)
    window.addEventListener('resize',h)
    return()=>window.removeEventListener('resize',h)
  },[])
  const go=p=>{setPage(p);setMobileOpen(false);window.scrollTo(0,0)}

  return(
    <>
      <nav style={{position:'fixed',top:0,left:0,right:0,zIndex:200,background:'rgba(68,68,68,0.98)',
        backdropFilter:'blur(8px)',borderBottom:`2px solid ${CR}`,
        display:'flex',alignItems:'center',justifyContent:'space-between',padding:'0 20px',height:62}}>

        {/* Logo */}
        <button onClick={()=>go('hjem')} style={{background:'none',border:'none',cursor:'pointer',
          display:'flex',alignItems:'center',gap:10,flexShrink:0}}>
          <Scales size={28}/>
          <span style={{fontFamily:'Georgia,serif',fontWeight:700,fontSize:15,letterSpacing:'0.1em',
            color:'white',textTransform:'uppercase'}}>
            POLITI<span style={{color:CR}}>JURI§</span>TENE
          </span>
        </button>

        {/* Desktop links */}
        {wide && (
          <div style={{display:'flex',alignItems:'center',gap:2,overflowX:'auto'}}>
            {PAGES.map(p=>(
              <button key={p.id} onClick={()=>go(p.id)} style={{
                background:'none',border:'none',cursor:'pointer',whiteSpace:'nowrap',
                color:page===p.id?'white':'rgba(255,255,255,0.65)',
                fontSize:12,fontWeight:700,letterSpacing:'0.06em',textTransform:'uppercase',
                padding:'8px 10px',
                borderBottom:page===p.id?`2px solid ${CR}`:'2px solid transparent',
                transition:'color .2s,border-color .2s',
              }}>{p.label}</button>
            ))}
            {user&&<div style={{marginLeft:10,background:CR,borderRadius:20,padding:'4px 12px',
              fontSize:11,fontWeight:800,color:'white',letterSpacing:'0.06em'}}>{initials(user.name)}</div>}
          </div>
        )}

        {/* Hamburger – only on narrow */}
        {!wide && (
          <button onClick={()=>setMobileOpen(o=>!o)} style={{
            background:mobileOpen?CR:'rgba(255,255,255,0.1)',border:'none',cursor:'pointer',
            borderRadius:4,width:44,height:44,display:'flex',flexDirection:'column',
            alignItems:'center',justifyContent:'center',gap:5,padding:'10px',
            transition:'background .2s',flexShrink:0,
          }}>
            {[0,1,2].map(i=>(
              <span key={i} style={{
                display:'block',height:2,width:'100%',background:'white',borderRadius:2,
                transform:mobileOpen&&i===0?'translateY(7px) rotate(45deg)':mobileOpen&&i===2?'translateY(-7px) rotate(-45deg)':'none',
                opacity:mobileOpen&&i===1?0:1,transition:'transform .25s,opacity .2s',
              }}/>
            ))}
          </button>
        )}
      </nav>

      {/* Mobile drawer */}
      <div style={{
        position:'fixed',top:62,left:0,right:0,bottom:0,zIndex:150,
        background:'rgba(20,20,20,0.97)',
        display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:0,
        transform:mobileOpen?'translateX(0)':'translateX(100%)',
        transition:'transform .3s cubic-bezier(.4,0,.2,1)',
        overflowY:'auto',
      }}>
        {PAGES.map(p=>(
          <button key={p.id} onClick={()=>go(p.id)} style={{
            background:'none',border:'none',cursor:'pointer',
            color:page===p.id?'white':'rgba(255,255,255,0.6)',
            fontSize:20,fontWeight:700,letterSpacing:'0.1em',textTransform:'uppercase',
            padding:'12px 0',borderBottom:'1px solid rgba(255,255,255,0.07)',
            width:260,textAlign:'center',
          }}>{p.label}</button>
        ))}
        {user&&<p style={{marginTop:24,fontSize:12,color:'rgba(255,255,255,0.35)'}}>Innlogget: {user.name}</p>}
      </div>
    </>
  )
}

/* ── LOGIN ── */
function LoginModal({onClose,onLogin}){
  const[u,setU]=useState('');const[p,setP]=useState('');const[err,setErr]=useState('')
  const submit=()=>{
    const f=USERS.find(x=>x.username===u.trim()&&x.password===p)
    if(f){onLogin(f);onClose()}else setErr('Feil brukernavn eller passord.')
  }
  const inp={width:'100%',padding:'10px 14px',border:'1px solid #ddd',fontSize:15,
    outline:'none',marginBottom:14,fontFamily:'inherit'}
  return(
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.65)',zIndex:300,
      display:'flex',alignItems:'center',justifyContent:'center',padding:20}} onClick={onClose}>
      <div style={{background:'white',width:'100%',maxWidth:360,padding:36,
        boxShadow:'0 24px 60px rgba(0,0,0,0.3)'}} onClick={e=>e.stopPropagation()}>
        <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:28}}>
          <Scales size={22}/><h2 style={{fontFamily:'Georgia,serif',fontSize:20,color:'#2a2a2a'}}>Redaktørinnlogging</h2>
        </div>
        {[['Brukernavn',u,setU,'text'],['Passord',p,setP,'password']].map(([l,v,s,t])=>(
          <div key={l}>
            <label style={{fontSize:11,fontWeight:700,letterSpacing:'0.12em',textTransform:'uppercase',
              color:'#999',display:'block',marginBottom:5}}>{l}</label>
            <input style={{...inp,marginTop:0}} type={t} value={v}
              onChange={e=>s(e.target.value)} onKeyDown={e=>e.key==='Enter'&&submit()} autoFocus={l==='Brukernavn'}/>
          </div>
        ))}
        {err&&<p style={{color:CR,fontSize:13,marginBottom:8}}>{err}</p>}
        <button onClick={submit} style={{width:'100%',background:CR,color:'white',border:'none',
          cursor:'pointer',padding:12,fontSize:15,fontWeight:700,marginTop:6}}>Logg inn</button>
        <button onClick={onClose} style={{width:'100%',background:'none',border:'none',cursor:'pointer',
          padding:9,fontSize:13,color:'#bbb',marginTop:4}}>Avbryt</button>
      </div>
    </div>
  )
}

/* ── WRAPPERS ── */
function Wrap({bg='white',children}){
  const m=useMobile()
  return(<div style={{background:bg,padding:m?'48px 16px':'80px 24px'}}><div style={{maxWidth:1100,margin:'0 auto'}}>{children}</div></div>)
}
function TwoCol({children}){
  const m=useMobile()
  return <div style={{display:'grid',gridTemplateColumns:m?'1fr':'1fr 1fr',gap:m?32:48,alignItems:'start'}}>{children}</div>
}

function Head({label,title,intro}){
  return(
    <div style={{marginBottom:50}}>
      <p style={{fontSize:11,fontWeight:700,letterSpacing:'0.2em',textTransform:'uppercase',color:CR,marginBottom:10}}>{label}</p>
      <div style={{width:48,height:2,background:CR,marginBottom:20}}/>
      <h2 style={{fontFamily:'Georgia,serif',fontSize:'clamp(26px,4vw,40px)',fontWeight:700,color:'#2a2a2a',lineHeight:1.15,marginBottom:intro?18:0}}>{title}</h2>
      {intro&&<p style={{fontSize:16,color:'#555',maxWidth:640,lineHeight:1.8}}>{intro}</p>}
    </div>
  )
}
function Btn({onClick,children,outline=false,style={}}){
  return(
    <button onClick={onClick} style={{
      background:outline?'none':CR,color:outline?CR:'white',
      border:outline?`1px solid ${CR}`:'none',cursor:'pointer',
      padding:'10px 22px',fontSize:13,fontWeight:700,letterSpacing:'0.06em',...style,
    }}>{children}</button>
  )
}

