/* ── AKTUELT ── */
function Aktuelt({user,news,setNews}){
  const[showForm,setShowForm]=useState(false)
  const[editing,setEditing]=useState(null)
  const[form,setForm]=useState({title:'',category:'Nyheter',body:''})
  const[delId,setDelId]=useState(null)
  const CATS=['Nyheter','Politikk','Lønn','Økonomi','Utdanning','Arrangement','Annet']
  const openNew=()=>{setForm({title:'',category:'Nyheter',body:''});setEditing(null);setShowForm(true)}
  const openEdit=item=>{setForm({title:item.title,category:item.category,body:item.body});setEditing(item.id);setShowForm(true)}
  const save=async()=>{
    if(!form.title.trim()||!form.body.trim())return
    const u=editing?news.map(n=>n.id===editing?{...n,...form}:n)
      :[{id:Date.now().toString(),date:new Date().toISOString().slice(0,10),author:user.name,...form},...news]
    setNews(u);await saveNews(u);setShowForm(false)
  }
  const remove=async id=>{const u=news.filter(n=>n.id!==id);setNews(u);await saveNews(u);setDelId(null)}
  const inp={width:'100%',padding:'10px 14px',border:'1px solid #ddd',fontSize:15,outline:'none',marginBottom:14,fontFamily:'inherit'}
  const lbl={fontSize:11,fontWeight:700,letterSpacing:'0.12em',textTransform:'uppercase',color:'#999',display:'block',marginBottom:5}
  const ov={position:'fixed',inset:0,background:'rgba(0,0,0,0.55)',zIndex:250,display:'flex',alignItems:'center',justifyContent:'center',padding:20}
  return(
    <Wrap>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',flexWrap:'wrap',gap:16}}>
        <Head label="Politijuristene" title="Aktuelt" intro="Siste nyheter og meldinger."/>
        {user&&<Btn onClick={openNew} style={{flexShrink:0}}>+ Legg ut nyhet</Btn>}
      </div>
      {showForm&&(
        <div style={ov}>
          <div style={{background:'white',width:'100%',maxWidth:560,padding:36,maxHeight:'90vh',overflowY:'auto'}}>
            <h3 style={{fontFamily:'Georgia,serif',fontSize:20,marginBottom:24}}>{editing?'Rediger nyhet':'Ny nyhet'}</h3>
            <label style={lbl}>Tittel *</label>
            <input style={inp} value={form.title} onChange={e=>setForm(f=>({...f,title:e.target.value}))} placeholder="Overskrift…"/>
            <label style={lbl}>Kategori</label>
            <select style={{...inp,background:'white'}} value={form.category} onChange={e=>setForm(f=>({...f,category:e.target.value}))}>
              {CATS.map(c=><option key={c}>{c}</option>)}
            </select>
            <label style={lbl}>Innhold *</label>
            <textarea style={{...inp,minHeight:160,resize:'vertical'}} value={form.body} onChange={e=>setForm(f=>({...f,body:e.target.value}))} placeholder="Tekst…"/>
            <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:4}}>
              <Btn onClick={()=>setShowForm(false)} outline>Avbryt</Btn>
              <Btn onClick={save}>{editing?'Lagre':'Publiser'}</Btn>
            </div>
          </div>
        </div>
      )}
      {delId&&(
        <div style={ov}>
          <div style={{background:'white',padding:36,maxWidth:340,width:'100%'}}>
            <h3 style={{fontFamily:'Georgia,serif',fontSize:18,marginBottom:10}}>Slett nyhet?</h3>
            <p style={{color:'#666',marginBottom:24}}>Kan ikke angres.</p>
            <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
              <Btn onClick={()=>setDelId(null)} outline>Avbryt</Btn>
              <button onClick={()=>remove(delId)} style={{background:'#c0392b',color:'white',border:'none',cursor:'pointer',padding:'10px 22px',fontSize:14,fontWeight:700}}>Slett</button>
            </div>
          </div>
        </div>
      )}
      <div style={{display:'flex',flexDirection:'column'}}>
        {news.length===0&&<p style={{color:'#bbb'}}>Ingen nyheter ennå.</p>}
        {news.map(item=>(
          <article key={item.id} style={{borderBottom:'1px solid #eee',padding:'28px 0'}}>
            <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:10,flexWrap:'wrap'}}>
              <span style={{background:CR,color:'white',fontSize:11,fontWeight:700,padding:'3px 10px',letterSpacing:'0.1em',textTransform:'uppercase'}}>{item.category}</span>
              <span style={{fontSize:13,color:'#aaa'}}>{fmtDate(item.date)}</span>
              <span style={{fontSize:13,color:'#ccc'}}>·</span>
              <span style={{fontSize:13,color:'#888'}}>{item.author}</span>
            </div>
            <h3 style={{fontFamily:'Georgia,serif',fontSize:21,fontWeight:700,color:'#2a2a2a',marginBottom:12,lineHeight:1.3}}>{item.title}</h3>
            {item.img&&<img src={item.img} alt="" style={{width:'100%',maxHeight:280,objectFit:'cover',marginBottom:18,display:'block'}}/>}
            <div style={{fontSize:15,color:'#555',lineHeight:1.8}}>
              {item.body.split('\n\n').map((para,i)=>(
                <p key={i} style={{marginBottom:14}}>{para}</p>
              ))}
            </div>
            {user&&(
              <div style={{display:'flex',gap:8,marginTop:12}}>
                <Btn onClick={()=>openEdit(item)} outline style={{fontSize:12,padding:'5px 14px'}}>Rediger</Btn>
                <button onClick={()=>setDelId(item.id)} style={{background:'none',border:'1px solid #ddd',cursor:'pointer',color:'#aaa',fontSize:12,padding:'5px 14px'}}>Slett</button>
              </div>
            )}
          </article>
        ))}
      </div>
      {!user&&<p style={{marginTop:28,fontSize:13,color:'#ccc',fontStyle:'italic'}}>Innloggede redaktører kan publisere nyheter. Innlogging via bunnteksten.</p>}
    </Wrap>
  )
}

/* ── I MEDIA ── */
function IMedia(){
  const[filter,setFilter]=useState('Alle')
  const types=['Alle',...Array.from(new Set(MEDIA.map(m=>m.type)))]
  const vis=filter==='Alle'?MEDIA:MEDIA.filter(m=>m.type===filter)
  return(
    <Wrap>
      <Head label="Presseklipp og medieomtale" title="I media" intro="Her samler vi presseoppslag og intervjuer der Politijuristene er sitert eller omtalt."/>
      <div style={{display:'flex',gap:8,flexWrap:'wrap',marginBottom:32}}>
        {types.map(t=>(
          <button key={t} onClick={()=>setFilter(t)} style={{
            padding:'6px 16px',fontSize:13,fontWeight:600,cursor:'pointer',border:'none',
            background:filter===t?CR:GB,color:filter===t?'white':'#555',
          }}>{t}</button>
        ))}
      </div>
      <div style={{display:'flex',flexDirection:'column',gap:2}}>
        {vis.map((m,i)=>(
          <div key={i} style={{background:i%2===0?GB:'white',padding:'16px 20px',
            display:'flex',alignItems:'center',justifyContent:'space-between',gap:16,flexWrap:'wrap'}}>
            <div style={{display:'flex',alignItems:'center',gap:14}}>
              <div style={{width:50,height:50,background:GD,flexShrink:0,display:'flex',
                alignItems:'center',justifyContent:'center',fontSize:9,fontWeight:800,
                color:'white',letterSpacing:'0.04em',textTransform:'uppercase',textAlign:'center',padding:'0 4px'}}>
                {m.outlet}
              </div>
              <div>
                <p style={{fontWeight:600,fontSize:15,color:'#2a2a2a',marginBottom:3}}>{m.title}</p>
                <p style={{fontSize:12,color:'#bbb'}}>{m.type} · {fmtDate(m.date)}</p>
              </div>
            </div>
            <a href={m.link} target="_blank" rel="noreferrer" style={{background:'none',border:`1px solid ${CR}`,color:CR,
              textDecoration:'none',padding:'6px 16px',fontSize:13,fontWeight:600,whiteSpace:'nowrap'}}>Les oppslag →</a>
          </div>
        ))}
      </div>
      <div style={{marginTop:40,background:GD,padding:28,color:'white'}}>
        <p style={{fontSize:11,fontWeight:700,letterSpacing:'0.15em',textTransform:'uppercase',color:'rgba(255,255,255,0.4)',marginBottom:8}}>Pressehenvendelser</p>
        <p style={{fontSize:15,color:'rgba(255,255,255,0.8)',lineHeight:1.75}}>
          Journalister kan kontakte leder direkte på <strong style={{color:'white'}}>post@politijuristene.no</strong>
        </p>
      </div>
    </Wrap>
  )
}

