/* ── STYRET ── */
function Styret(){
  const groups=[
    {label:'Leder og nestledere',types:['leder','nestleder']},
    {label:'Styremedlemmer',types:['styre']},
    {label:'Varamedlemmer',types:['vara']},
  ]
  return(
    <Wrap bg={GB}>
      <Head label="Styreperioden 2023–2025" title="Styret i Politijuristene"
        intro="Styret består av erfarne tillitsvalgte fra politidistrikt og særorgan over hele landet."/>
      {groups.map(g=>(
        <div key={g.label} style={{marginBottom:44}}>
          <h3 style={{fontSize:11,fontWeight:700,letterSpacing:'0.15em',textTransform:'uppercase',
            color:GD,marginBottom:16,paddingBottom:10,borderBottom:'1px solid #ddd'}}>{g.label}</h3>
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(240px,1fr))',gap:10}}>
            {STYRET.filter(m=>g.types.includes(m.type)).map(m=>(
              <div key={m.name} style={{background:'white',padding:20,display:'flex',gap:12,alignItems:'flex-start',
                borderLeft:`4px solid ${m.type==='leder'?CR:m.type==='nestleder'?GD:'#ddd'}`}}>
                <div style={{width:40,height:40,borderRadius:'50%',flexShrink:0,
                  background:m.type==='leder'?CR:m.type==='nestleder'?GD:'#c0c0c0',
                  display:'flex',alignItems:'center',justifyContent:'center',
                  fontSize:13,fontWeight:700,color:'white'}}>{initials(m.name)}</div>
                <div>
                  <p style={{fontWeight:700,fontSize:14,color:'#2a2a2a',marginBottom:2}}>{m.name}</p>
                  <p style={{fontSize:12,color:CR,fontWeight:600,marginBottom:2}}>{m.role}</p>
                  <p style={{fontSize:12,color:'#888'}}>{m.title}</p>
                  <p style={{fontSize:11,color:'#bbb'}}>{m.district}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
      <h3 style={{fontSize:11,fontWeight:700,letterSpacing:'0.15em',textTransform:'uppercase',
        color:GD,marginBottom:14,paddingBottom:10,borderBottom:'1px solid #ddd'}}>Valgkomiteen</h3>
      <div style={{display:'flex',gap:10,flexWrap:'wrap'}}>
        {VALGKOMITE.map(m=>(
          <div key={m.name} style={{background:'white',padding:'14px 20px',borderLeft:'4px solid #e0e0e0'}}>
            <p style={{fontWeight:700,fontSize:14,color:'#2a2a2a'}}>{m.name}</p>
            <p style={{fontSize:12,color:'#bbb'}}>{m.district}</p>
          </div>
        ))}
      </div>
    </Wrap>
  )
}

/* ── HISTORIE ── */
function Historie(){
  const ev=[
    {y:'1907',t:'Initiativet tas',d:'Politimester Oscar Heyerdahl i Kragerø tar initiativet til å danne en forening for politiembetsmennene. 78 menn i stillingene – krav om lønnsforhøyelse var drivkraften.'},
    {y:'1908',t:'Politiembetsmennenes Landsforening stiftes',d:'Foreningen etableres med bevisst profesjonsstolthet – ikke bare lønnskamp, men faglig og kollegialt fellesskap.'},
    {y:'2008',t:'Navnebytte til Politijuristene',d:'Etter 100 år skifter foreningen navn til Politijuristene – bedre reflekterer det mangfoldige juridiske medlemskapet.'},
    {y:'2021',t:'Gjennomslag for grunnutdanning',d:'Politijuristene får gjennomslag for en 3-årig grunnutdanning for påtalejurister med 15 studiepoeng.'},
    {y:'2023',t:'Eget budsjettkapittel for påtale',d:'Etter langvarig påvirkningsarbeid får påtalemyndigheten i politiet sitt eget budsjettkapittel (4.4.3) – historisk.'},
    {y:'2024',t:'Streik og 80 mill. ekstra',d:'Første streik på 16 år. RNB 2024 tilføres 80 mill. ekstra. Nytt gradssystem med fire grader vedtas.'},
    {y:'2025',t:'Påtaleløft på agendaen',d:'74 % av porteføljejuristene har ikke tid til å etterleve riksadvokatens rundskriv. Politijuristene krever 250 nye jurister.'},
  ]
  return(
    <Wrap>
      <Head label="Siden 1908" title="Vår historie" intro="Fra et lite initiativ av en politimester i Kragerø til en av de viktigste fagforeningene i norsk rettsstat."/>
      <div style={{position:'relative',paddingLeft:30}}>
        <div style={{position:'absolute',left:9,top:0,bottom:0,width:2,background:'#e8e8e8'}}/>
        {ev.map((e,i)=>(
          <div key={e.y} style={{position:'relative',marginBottom:36}}>
            <div style={{position:'absolute',left:-25,top:5,width:14,height:14,borderRadius:'50%',
              background:i===ev.length-1?CR:'white',border:`2px solid ${CR}`}}/>
            <span style={{fontSize:11,fontWeight:700,letterSpacing:'0.15em',color:CR,textTransform:'uppercase'}}>{e.y}</span>
            <h3 style={{fontFamily:'Georgia,serif',fontSize:18,fontWeight:700,color:'#2a2a2a',margin:'5px 0 7px'}}>{e.t}</h3>
            <p style={{fontSize:15,color:'#555',lineHeight:1.8,maxWidth:660}}>{e.d}</p>
          </div>
        ))}
      </div>
    </Wrap>
  )
}

/* ── HANDLINGSPLAN ── */
function Handlingsplan(){
  const areas=[
    {num:'I',title:'Lønn og arbeidsvilkår',color:CR,items:['Arbeide for best mulig lønns- og arbeidsvilkår for alle medlemmer.','Sikre at jurister foretrekkes til mellom- og topplederstillinger.','Delta i HMS-arbeid og arbeide for forsvarlig arbeidsbelastning.','Arbeide for relevant etterutdanningstilbud med sertifiseringskrav.','Bidra til å etablere alternative karriereveier via nye stillingskoder.']},
    {num:'II',title:'Interessepolitikk og media',color:GD,items:['Påvirke Stortinget, JD og POD for tilstrekkelige ressurser til påtale.','Opprettholde løpende dialog med Stortinget, POD og Riksadvokaten.','Arbeide for at straffesaksbehandling er del av den justispolitiske debatt.','Avgis høringsuttalelser på relevante områder.','Være en tydelig aktør i mediebildet om påtalemyndighetens rolle.']},
    {num:'III',title:'Organisasjonsutvikling',color:'#7f8c8d',items:['Rekruttere og beholde dyktige tillitsvalgte lokalt og sentralt.','Utvikle og vedlikeholde nettside for medlemmenes informasjonsbehov.','Etablere «PJ-skolen» – seminar for nye tillitsvalgte i politiet.','Arrangere lokallagsledersamlinger minimum fire ganger i året.']},
  ]
  return(
    <Wrap bg={GB}>
      <Head label="Vedtatt av landsmøtet" title="Handlingsplan 2023–2025" intro="Politijuristenes strategiske prioriteringer for styreperioden."/>
      <div style={{display:'flex',flexDirection:'column',gap:24}}>
        {areas.map(a=>(
          <div key={a.num} style={{background:'white'}}>
            <div style={{background:a.color,padding:'12px 26px',display:'flex',alignItems:'center',gap:12}}>
              <span style={{fontFamily:'Georgia,serif',fontSize:24,fontWeight:700,color:'rgba(255,255,255,0.45)'}}>{a.num}</span>
              <h3 style={{fontFamily:'Georgia,serif',fontSize:18,fontWeight:700,color:'white'}}>{a.title}</h3>
            </div>
            <ul style={{padding:'20px 26px 24px',listStyle:'none',display:'flex',flexDirection:'column',gap:9}}>
              {a.items.map((item,i)=>(
                <li key={i} style={{display:'flex',gap:12,alignItems:'flex-start'}}>
                  <span style={{width:5,height:5,borderRadius:'50%',background:a.color,flexShrink:0,marginTop:8}}/>
                  <p style={{fontSize:15,color:'#444',lineHeight:1.7}}>{item}</p>
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </Wrap>
  )
}

/* ── DOKUMENTER ── */
function Dokumenter({user}){
  const[filter,setFilter]=useState('Alle')
  const cats=['Alle',...Array.from(new Set(DOCS.map(d=>d.cat)))]
  const vis=filter==='Alle'?DOCS:DOCS.filter(d=>d.cat===filter)
  return(
    <Wrap>
      <Head label="Sentrale avtaler og dokumenter" title="Dokumenter"
        intro="Sentrale avtaler, vedtekter, resolusjoner og andre viktige dokumenter for Politijuristenes medlemmer."/>
      <div style={{display:'flex',gap:8,flexWrap:'wrap',marginBottom:28}}>
        {cats.map(c=>(
          <button key={c} onClick={()=>setFilter(c)} style={{padding:'6px 14px',fontSize:13,fontWeight:600,
            cursor:'pointer',border:'none',background:filter===c?CR:GB,color:filter===c?'white':'#555'}}>{c}</button>
        ))}
      </div>
      <div style={{display:'flex',flexDirection:'column',gap:2}}>
        {vis.map((d,i)=>(
          <div key={i} style={{background:i%2===0?GB:'white',padding:'15px 20px',
            display:'flex',alignItems:'center',justifyContent:'space-between',gap:16,flexWrap:'wrap'}}>
            <div style={{display:'flex',alignItems:'center',gap:14}}>
              <div style={{width:36,height:36,background:CR,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                <svg width={17} height={17} viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth={2} strokeLinecap="round">
                  <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
                  <polyline points="14 2 14 8 20 8"/>
                </svg>
              </div>
              <div>
                <p style={{fontWeight:600,fontSize:14,color:'#2a2a2a'}}>{d.name}</p>
                <p style={{fontSize:11,color:'#bbb'}}>{d.cat} · {d.date}</p>
              </div>
            </div>
            <a href={d.link} target="_blank" rel="noreferrer" style={{background:'none',border:`1px solid ${CR}`,color:CR,
              textDecoration:'none',padding:'5px 14px',fontSize:12,fontWeight:600,whiteSpace:'nowrap',
              opacity: d.link==='#' ? 0.4 : 1, pointerEvents: d.link==='#' ? 'none' : 'auto',
            }}>{d.link==='#' ? 'Kommer' : 'Last ned'}</a>
          </div>
        ))}
      </div>
      {user&&<div style={{marginTop:24,padding:20,background:GB,borderTop:`3px solid ${CR}`}}>
        <p style={{fontSize:11,fontWeight:700,letterSpacing:'0.1em',textTransform:'uppercase',color:'#999',marginBottom:8}}>Redaktør</p>
        <Btn onClick={()=>{}}>+ Last opp dokument</Btn>
      </div>}
    </Wrap>
  )
}

/* ── KONTAKT ── */
function Kontakt(){
  const[form,setForm]=useState({name:'',email:'',subject:'',msg:''})
  const[sent,setSent]=useState(false)
  const inp={width:'100%',padding:'10px 14px',border:'1px solid #ddd',fontSize:15,outline:'none',marginBottom:14,fontFamily:'inherit'}
  const lbl={fontSize:11,fontWeight:700,color:'#999',letterSpacing:'0.1em',textTransform:'uppercase',display:'block',marginBottom:5}
  return(
    <Wrap bg={GB}>
      <Head label="Ta kontakt" title="Kontakt oss" intro="Spørsmål om medlemskap, arbeidsvilkår eller annet?"/>
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(280px,1fr))',gap:44}}>
        <div>
          {[{icon:'M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z',l:'Adresse',v:'Juristenes Hus, Chr. Krohgs gate 12, 0186 Oslo'},
            {icon:'M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2zM22 6l-10 7L2 6',l:'E-post',v:'post@politijuristene.no'}].map(c=>(
            <div key={c.l} style={{display:'flex',gap:14,alignItems:'flex-start',marginBottom:20}}>
              <div style={{width:36,height:36,background:CR,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth={2} strokeLinecap="round"><path d={c.icon}/></svg>
              </div>
              <div>
                <p style={{fontSize:10,fontWeight:700,letterSpacing:'0.12em',textTransform:'uppercase',color:'#bbb',marginBottom:3}}>{c.l}</p>
                <p style={{fontSize:15,color:'#333'}}>{c.v}</p>
              </div>
            </div>
          ))}
          <div style={{background:GD,padding:26,marginTop:14,color:'white'}}>
            <h3 style={{fontFamily:'Georgia,serif',fontSize:17,color:'white',marginBottom:10}}>Bli medlem</h3>
            <p style={{fontSize:14,color:'rgba(255,255,255,0.7)',lineHeight:1.75,marginBottom:16}}>Er du jurist i politiet? Innmelding skjer gjennom Juristforbundet.</p>
            <a href="https://www.juristforbundet.no" target="_blank" rel="noreferrer" style={{display:'inline-block',background:CR,color:'white',textDecoration:'none',padding:'9px 22px',fontSize:13,fontWeight:700}}>Meld deg inn →</a>
          </div>
        </div>
        <div style={{background:'white',padding:30}}>
          {sent?(
            <div style={{textAlign:'center',padding:'36px 0'}}>
              <div style={{width:52,height:52,borderRadius:'50%',background:CR,display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 16px'}}>
                <svg width={24} height={24} viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth={2.5} strokeLinecap="round"><polyline points="20 6 9 17 4 12"/></svg>
              </div>
              <h3 style={{fontFamily:'Georgia,serif',fontSize:19,marginBottom:8}}>Takk!</h3>
              <p style={{color:'#999'}}>Vi svarer deg snart.</p>
              <Btn onClick={()=>setSent(false)} outline style={{marginTop:20}}>Send ny</Btn>
            </div>
          ):(
            <>
              <h3 style={{fontFamily:'Georgia,serif',fontSize:18,marginBottom:20,color:'#2a2a2a'}}>Send oss en melding</h3>
              {[['Navn *','name','text'],['E-post *','email','email'],['Emne','subject','text']].map(([l,k,t])=>(
                <div key={k}>
                  <label style={lbl}>{l}</label>
                  <input style={inp} type={t} value={form[k]} onChange={e=>setForm(f=>({...f,[k]:e.target.value}))}/>
                </div>
              ))}
              <label style={lbl}>Melding *</label>
              <textarea style={{...inp,minHeight:120,resize:'vertical'}} value={form.msg} onChange={e=>setForm(f=>({...f,msg:e.target.value}))}/>
              <Btn onClick={()=>{if(form.name&&form.email&&form.msg)setSent(true)}} style={{width:'100%',padding:12,fontSize:15}}>Send melding</Btn>
            </>
          )}
        </div>
      </div>
    </Wrap>
  )
}

/* ── FOOTER ── */
function Footer({onLoginClick,user,onLogout}){
  return(
    <footer style={{background:'#181818',padding:'28px 24px'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',flexWrap:'wrap',gap:16,marginBottom:16}}>
        <div style={{display:'flex',alignItems:'center',gap:16,flexWrap:'wrap'}}>
          <Scales size={24} color={CR}/>
          <span style={{fontSize:13,fontWeight:700,letterSpacing:'0.1em',textTransform:'uppercase',color:'rgba(255,255,255,0.5)'}}>
            POLITI<span style={{color:CR}}>JURI§</span>TENE
          </span>
          <span style={{width:1,height:18,background:'rgba(255,255,255,0.1)',display:'block'}}/>
          <span style={{fontSize:12,color:'rgba(255,255,255,0.3)'}}>En del av Juristforbundet · Akademikerne</span>
        </div>
        <span style={{fontSize:12,color:'rgba(255,255,255,0.25)'}}>© 2025 Politijuristene · siden 1908</span>
      </div>
      {/* Subtil redaktørinnlogging */}
      <div style={{borderTop:'1px solid rgba(255,255,255,0.05)',paddingTop:12,display:'flex',alignItems:'center',gap:12}}>
        {user?(
          <>
            <span style={{fontSize:12,color:'rgba(255,255,255,0.25)'}}>Innlogget: {user.name}</span>
            <button onClick={onLogout} style={{background:'none',border:'none',cursor:'pointer',
              color:'rgba(255,255,255,0.25)',fontSize:12,textDecoration:'underline',padding:0}}>Logg ut</button>
          </>
        ):(
          <button onClick={onLoginClick} style={{background:'none',border:'none',cursor:'pointer',
            color:'rgba(255,255,255,0.18)',fontSize:12,textDecoration:'underline',padding:0,letterSpacing:'0.03em'}}>
            Redaktørinnlogging
          </button>
        )}
      </div>
    </footer>
  )
}

/* ── APP ── */
export default function App(){
  const[page,setPage]=useState('hjem')
  const[user,setUser]=useState(null)
  const[showLogin,setLogin]=useState(false)
  const[mobileOpen,setMob]=useState(false)
  const[news,setNews]=useState(SEED)
  const[loading,setLoading]=useState(true)

  useEffect(()=>{ loadNews().then(n=>{setNews(n);setLoading(false)}) },[])

  const navigate=p=>{setPage(p);setMob(false);window.scrollTo(0,0)}

  return(
    <div style={{minHeight:'100vh',display:'flex',flexDirection:'column',fontFamily:'system-ui,sans-serif'}}>
      <Nav page={page} setPage={navigate} user={user} mobileOpen={mobileOpen} setMobileOpen={setMob}/>
      {showLogin&&<LoginModal onClose={()=>setLogin(false)} onLogin={u=>{setUser(u);setLogin(false)}}/>}
      <main style={{flex:1,paddingTop:page==='hjem'?0:62}}>
        {page==='hjem'          && <Hjem setPage={navigate} news={news}/>}
        {page==='aktuelt'       && (loading?<Wrap><p style={{color:'#bbb'}}>Laster…</p></Wrap>:<Aktuelt user={user} news={news} setNews={setNews}/>)}
        {page==='i-media'       && <IMedia/>}
        {page==='politikk'      && <Politikk/>}
        {page==='styret'        && <Styret/>}
        {page==='historie'      && <Historie/>}
        {page==='handlingsplan' && <Handlingsplan/>}
        {page==='dokumenter'    && <Dokumenter user={user}/>}
        {page==='kontakt'       && <Kontakt/>}
      </main>
      <Footer onLoginClick={()=>setLogin(true)} user={user} onLogout={()=>setUser(null)}/>
    </div>
  )
}
